时隔五个月,开始重新学习mysql,忘完了,不过没事儿,本来也没学太多,这次记下来
创建数据库//命令后都要加分号create database world ; //创建以 world 为库名的数据库show databases ; // 显示数据库列表use world ; // 选择 world 数据库show tables ; // 显示 world 下所有表名describe 表名(此处使用city) ; // 显示 city 数据表的结构delete from 表名 ; // 清空表中记录

删除数据库DROP DATABASE 数据库名 ; 

创建数据库表// Field - Type - Null - Key - Default - Extra// 都有这六个参数CREATE TABLE users(      id INT AUTO_INCREMENT PRIMARY KEY,    username VARCHAR(50),    password VARCHAR(100) );

删除数据库表drop TABLE 表名 ;

MySQL插入数据INSERT INTO 表名 (column1, column2, column3, ...) // 表中的列名VALUES (value1, value2, value3, ...);// 例如这样INSERT INTO users2 (username, password) VALUES     (&#x27;miao&#x27;, &#x27;111111&#x27;),    (&#x27;wang&#x27;, &#x27;222222&#x27;),    (&#x27;kele&#x27;, &#x27;333333&#x27;);// 插入完可以看一下啦SELECT * FROM users;

MySQL删除数据DELETE FROM table_nameWHERE condition;//比如DELETE FROM usersWHERE id = 3;//删连续多行DELETE FROM users WHERE id BETWEEN 5 AND 10;//删不连续多行DELETE FROM users WHERE id IN (2, 5, 8);

MySQL改写数据

MySQL查询数据SELECT column1, column2, ...FROM 表名




MySQL shell 启动命令 : mysqlsh
连接数据库 \connect root@ localhost
MySQL 启动 : mysql -u &lt;用户名&gt;(默认为root) -p

